import axios from "axios";
import { useState } from "react";

const EVENT_BOOKING_API = "https://calebtonny.alwaysdata.net/api/event-booking";
useEffect(() => {
  axios.get(EVENT_BOOKING_API)
    .then(res => console.log(res.data))
    .catch(err => console.error(err));
}, []);

const EventBooking = () => {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    event_date: "",
    guests: "",
    message: ""
  });

  const handleChange = (e) => {
    setForm({...form, [e.target.name]: e.target.value});
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post("https://calebtonny.alwaysdata.net/api/event_booking",form);
      alert(res.data);
    } catch (err) {
      console.error(err);
      alert(
        err.response
          ? "Error submitting booking"
          : "The event booking server is not reachable right now. Check your backend or alwaysdata deployment."
      );
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input name="name" placeholder="Name" onChange={handleChange} />
      <input name="email" placeholder="Email" onChange={handleChange} />
      <input name="phone" placeholder="Phone" onChange={handleChange} />
      <input type="date" name="event_date" onChange={handleChange} />
      <input name="guests" placeholder="Guests" onChange={handleChange} />
      <textarea name="message" placeholder="Message" onChange={handleChange}></textarea>

      <button type="submit">Send Request</button>
    </form>
  );
};

export default EventBooking;
